const row = $input.first().json;

// --- helpers ---
function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}
function fmtNum(v, dec) {
  if (v === null || v === undefined) return null;
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  return n.toLocaleString('en-US', {
    minimumFractionDigits: dec || 0,
    maximumFractionDigits: dec || 0
  });
}
function statLabel(key) {
  const map = {
    'hp': 'HP', 'decay': 'Decay Rate', 'regen-per-sec': 'Regen/s',
    'delay-down-sec': 'Delay (Down, s)', 'delay-damage-sec': 'Delay (Damage, s)',
    'speed-mms': 'Speed (mm/s)', 'spool-sec': 'Spool (s)', 'fuel-per-gm': 'Fuel/Gm',
    'cooldown-sec': 'Cooldown (s)', 'fuel': 'Fuel Capacity', 'q-fuel': 'Q-Fuel Capacity',
    'max-range-m': 'Max Range (m)', 'ideal-range-m': 'Ideal Range (m)',
    'damage-per-shot': 'Damage/Shot', 'fire-rate-per-min': 'Fire Rate (RPM)',
    'projectile-speed-mps': 'Projectile Speed (m/s)',
    'ammo': 'Ammo', 'damage': 'Damage', 'fov-deg': 'FOV (°)',
    'range-m': 'Range (m)', 'tracking': 'Tracking', 'speed-mps': 'Speed (m/s)',
    'lifetime-sec': 'Lifetime (s)', 'lock-time-sec': 'Lock Time (s)',
    'power': 'Power Output', 'power-draw': 'Power Draw',
    'cooling': 'Cooling Rate', 'heat': 'Heat Gen',
    'volume': 'Volume (SCU)', 'scu': 'SCU',
    'force': 'Force', 'range': 'Range'
  };
  return map[key] || key.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

const slug = row.slug || (row.class || row.name || 'unknown')
  .toLowerCase().replace(/_/g, '-').replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');

const uexPrices  = parsePrices(row.uex_prices);
const dp4kPrices = parsePrices(row.datap4k_prices);

const lines = [];
lines.push('# ' + row.name);
lines.push('');

// Core attributes
lines.push('- **Category:** ' + (row.uex_category_name || row.type || 'Component'));
if (row.uex_category_section) lines.push('- **Section:** ' + row.uex_category_section);
if (row.type && row.type !== row.uex_category_name) lines.push('- **Type:** ' + row.type);
if (row.sub_type) lines.push('- **Subtype:** ' + row.sub_type);
if (row.manufacturer) lines.push('- **Manufacturer:** ' + row.manufacturer);
if (row.size) lines.push('- **Size:** S' + row.size);
if (row.grade) lines.push('- **Grade:** ' + row.grade);
lines.push('');

// Stats table
const stats = (typeof row.stats === 'string') ? JSON.parse(row.stats || '{}') : (row.stats || {});
const statKeys = Object.keys(stats).filter(k => stats[k] !== null && stats[k] !== undefined && stats[k] !== 0);
if (statKeys.length > 0) {
  lines.push('## Stats');
  lines.push('');
  lines.push('| Stat | Value |');
  lines.push('|---|---|');
  for (const k of statKeys) {
    const v = stats[k];
    const display = (typeof v === 'number') ? fmtNum(v, 2) : String(v);
    lines.push('| ' + statLabel(k) + ' | ' + display + ' |');
  }
  lines.push('');
}

// Pricing
if (uexPrices.length > 0) {
  lines.push('## Where to Buy (Live UEX Prices)');
  lines.push('');
  lines.push('| Terminal | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|');
  for (const p of uexPrices) {
    const buy  = p.buy  ? Number(p.buy).toLocaleString('en-US')  : '—';
    const sell = p.sell ? Number(p.sell).toLocaleString('en-US') : '—';
    lines.push('| ' + p.terminal + ' | ' + buy + ' | ' + sell + ' |');
  }
  lines.push('');
} else if (dp4kPrices.length > 0) {
  lines.push('## Where to Buy (DataPack Prices)');
  lines.push('');
  lines.push('| Shop | Location | Buy (aUEC) | Sell (aUEC) |');
  lines.push('|---|---|---|---|');
  for (const p of dp4kPrices) {
    const buy  = p.buy  ? Number(p.buy).toLocaleString('en-US')  : '—';
    const sell = p.sell ? Number(p.sell).toLocaleString('en-US') : '—';
    lines.push('| ' + p.shop + ' | ' + p.location + ' | ' + buy + ' | ' + sell + ' |');
  }
  lines.push('');
} else {
  lines.push('## Pricing');
  lines.push('');
  lines.push('No purchase pricing currently available.');
  lines.push('');
}

return [{
  json: {
    slug,
    markdown_detailed: lines.join('\n')
  }
}];

const item = $input.first().json;
const slug    = (item.slug || '').replace(/'/g, "''");
const content = (item.markdown_detailed || '').replace(/'/g, "''");
const query = "INSERT INTO kb_content (entity_slug, entity_type, entity_id, content, source_workflow, generated_at, updated_at) "
  + "VALUES ('" + slug + "', 'component', NULL, '" + content + "', 'KB - Components Markdown v1', now(), now()) "
  + "ON CONFLICT (entity_slug, entity_type) DO UPDATE SET content = EXCLUDED.content, "
  + "source_workflow = EXCLUDED.source_workflow, generated_at = EXCLUDED.generated_at, updated_at = now()";
return [{ json: { query, entity_slug: item.slug } }];
